import React, { useState, useEffect } from 'react';
import { gamesAPI, ordersAPI, adminAPI } from '../services/api';
import { useAuth } from '../context/AuthContext';
import ImageUpload from '../components/ImageUpload';

interface Game {
  _id: string;
  title: string;
  description: string;
  price: number;
  platform: string;
  region: string;
  images: string[];
  availability: string;
  accountDetails?: {
    username: string;
    email: string;
    additionalInfo: string;
  };
  createdAt: string;
  updatedAt: string;
}

interface Order {
  _id: string;
  user: {
    email: string;
    firstName: string;
    lastName: string;
  };
  games: Array<{
    game: {
      _id: string;
      title: string;
      platform: string;
      price: number;
    };
    price: number;
  }>;
  totalAmount: number;
  status: string;
  createdAt: string;
}

interface User {
  _id: string;
  email: string;
  firstName: string;
  lastName: string;
  role: string;
  createdAt: string;
}

const AdminDashboard: React.FC = () => {
  const { state } = useAuth();
  const [activeTab, setActiveTab] = useState<'games' | 'orders' | 'users'>('games');
  const [games, setGames] = useState<Game[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(false);
  const [showAddGameForm, setShowAddGameForm] = useState(false);
  const [editingGame, setEditingGame] = useState<Game | null>(null);

  const [gameForm, setGameForm] = useState({
    title: '',
    description: '',
    price: '',
    platform: 'PC',
    region: 'Global',
    availability: 'available',
    images: [] as string[],
    accountDetails: {
      username: '',
      email: '',
      additionalInfo: ''
    }
  });

  const resetGameForm = () => {
    setGameForm({
      title: '',
      description: '',
      price: '',
      platform: 'PC',
      region: 'Global',
      availability: 'available',
      images: [] as string[],
      accountDetails: {
        username: '',
        email: '',
        additionalInfo: ''
      }
    });
  };

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [gamesRes, ordersRes, usersRes] = await Promise.all([
        adminAPI.getGames(),
        adminAPI.getOrders(),
        adminAPI.getUsers()
      ]);
      setGames(gamesRes.data);
      setOrders(ordersRes.data);
      setUsers(usersRes.data);
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleGameSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const gameData = {
        ...gameForm,
        price: parseFloat(gameForm.price),
        images: gameForm.images
      };

      if (editingGame) {
        await gamesAPI.updateGame(editingGame._id, gameData);
      } else {
        await gamesAPI.createGame(gameData);
      }

      setShowAddGameForm(false);
      setEditingGame(null);
      resetGameForm();
      fetchData();
    } catch (error) {
      console.error('Error saving game:', error);
    }
  };

  const handleEditGame = (game: Game) => {
    setEditingGame(game);
    setGameForm({
      title: game.title,
      description: game.description,
      price: game.price.toString(),
      platform: game.platform,
      region: game.region,
      availability: game.availability,
      images: game.images || [],
      accountDetails: game.accountDetails || {
        username: '',
        email: '',
        additionalInfo: ''
      }
    });
    setShowAddGameForm(true);
  };

  const handleDeleteGame = async (gameId: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذا الحساب؟')) {
      try {
        await gamesAPI.deleteGame(gameId);
        fetchData();
      } catch (error) {
        console.error('Error deleting game:', error);
      }
    }
  };

  const handleUpdateOrderStatus = async (orderId: string, status: string) => {
    try {
      await adminAPI.updateOrderStatus(orderId, status);
      fetchData();
    } catch (error) {
      console.error('Error updating order status:', error);
    }
  };

  if (!state.isAuthenticated || state.user?.role !== 'admin') {
    return (
      <div className="min-h-screen bg-gray-50">
